form:Form.form:Scripts:
		function SueldoBruto()
{                               
	if (Ctrl('l_sueldo_bruto').GetXValue() == "1")
	{                                  
		Ctrl('l_sueldo_neto').SetCValue("");
		CtrlEnabled('l_sueldo_neto', false);
	}else
	{
		CtrlEnabled('l_sueldo_neto', true);
	}
}

function SueldoNeto()
{    
	if (Ctrl('l_sueldo_neto').GetXValue() == "1")
	{                                                  
		Ctrl('l_sueldo_bruto').SetCValue("");
		CtrlEnabled('l_sueldo_bruto', false);
	}else
	{
		CtrlEnabled('l_sueldo_bruto', true);
	}
}

function CallDescuentos(me)
{
	if (Ctrl('main').GetMode() == "EDIT" && Ctrl('l_liquida').GetCValue() == "0")
	{
		if (Ctrl('c_estado').GetXValue() == "I" || Ctrl('c_estado').GetXValue() == "A")
		{
	  	me.DoEvent("CALL_EDIT");
	  	return;
	  }
	}
	me.DoEvent("CALL_SHOW");
}

function ONLOAD()
{	
	if (Ctrl('main').GetMode() == "NEW")
	{
		Ctrl('c_estado').SetXValue("I");
	}

	/*
	CtrlEnabled('oi_concepto', false);
	if (Ctrl('l_liquida').GetCValue() == "1" && Ctrl('c_tipo_embargo').GetXValue() == "CAC")
	{
		CtrlEnabled('oi_concepto', true);	
	} */                              

	if (Ctrl('main').GetMode() == "EDIT")
	{
		CambioTipo();

		if (Ctrl('c_estado').GetXValue() != "I" && Ctrl('c_estado').GetXValue() != "A")
		{
			CtrlEnabled('e_nro_oficio', false);
			CtrlEnabled('f_oficio' , false);
			CtrlEnabled('o_embargo' , false);
			CtrlEnabled('n_monto_pend', false);
			CtrlEnabled('n_monto_total', false);
			CtrlEnabled('n_monto_fijo', false);
			CtrlEnabled('l_sueldo_neto', false);
			CtrlEnabled('n_porc_emb', false);
			CtrlEnabled('f_recepcion', false);
			CtrlEnabled('l_liquida', false);
			CtrlEnabled('o_caratula', false);
			CtrlEnabled('d_actor', false);
			CtrlEnabled('d_causa', false);
			CtrlEnabled('c_tipo_embargo', false);
			CtrlEnabled('oi_sucursal', false);
			CtrlEnabled('oi_sucursal_2', false);
			CtrlEnabled('d_juzgado', false);
			CtrlEnabled('d_juez', false);
			CtrlEnabled('d_secretaria', false);
			CtrlEnabled('c_nro_expediente', false);
			CtrlEnabled('c_nro_cuenta', false);
			CtrlEnabled('f_inicio', false);
			CtrlEnabled('f_inactivo', false);
			CtrlEnabled('f_finalizado', false);
			CtrlEnabled('c_estado', false); 	
			CtrlEnabled('l_sueldo_bruto', false);
			CtrlEnabled('oi_concepto', false);
		}

		if (Ctrl('c_tipo_embargo').GetXValue() == "OC" && Ctrl('l_liquida').GetCValue() == "0")
		{
	 		Ctrl('n_monto_pend').SetTypedValue(Ctrl('n_monto_total').TypedValue() - str2number(Ctrl('suma').GetXValue()));
	 		if (Ctrl('n_monto_pend').TypedValue() == 0)
	 		{
	 			Ctrl('c_estado').SetXValue("F");
	 			Ctrl('f_finalizado').SetXValue(date2str(Now()));
	 		}else if (Ctrl('n_monto_pend').TypedValue() > 0)
	 		{
	 			if (Ctrl('n_monto_pend').TypedValue() < Ctrl('n_monto_total').TypedValue())
	 				Ctrl('c_estado').SetXValue("A");
	 				Ctrl('f_finalizado').SetXValue("");
	 			if (Ctrl('n_monto_pend').TypedValue() == Ctrl('n_monto_total').TypedValue())
	 				Ctrl('c_estado').SetXValue("I");
	 				Ctrl('f_finalizado').SetXValue("");
	 		}else
	 		{
	 			alert('El monto de los descuentos excede el monto total del embargo');
	 		}
	 	}
	}

 	CtrlEnabled('DELETE', false);
 	if (Ctrl('c_estado').GetXValue() == "I")
 	{
 		CtrlEnabled('DELETE', true) 
 	}


 	CtrlEnabled('FINALIZAR', false);
 	if (Ctrl('l_liquida').GetCValue() == "0")
 	{
 		if (Ctrl('c_estado').GetXValue() == "I" || Ctrl('c_estado').GetXValue() == "A" )
 		{
 			CtrlEnabled('FINALIZAR', true);
	 	}
 	}

 	CtrlEnabled('INACTIVAR', false);	
	if (Ctrl('c_estado').GetXValue() == "I" || Ctrl('c_estado').GetXValue() == "A" || Ctrl('c_estado').GetXValue() == "N")
	{
		CtrlEnabled('INACTIVAR', true);
	}
}

function Aceptar()
{        
	if (Ctrl('c_tipo_embargo').GetXValue() == "CA")
	{
		if (Ctrl('n_porc_emb').TypedValue() != 0 && Ctrl('n_porc_emb').TypedValue() != null && Ctrl('l_sueldo_bruto').GetCValue() == 0 && Ctrl('l_sueldo_neto').GetCValue() == 0 && Ctrl('oi_concepto').GetXValue() == "")
		{
			alert("Al cargar un porcentaje de descuento debe indicar si la base es el sueldo neto, el bruto, o un concepto.");
		 	return false;
		}
		if ((Ctrl('n_porc_emb').TypedValue() == 0 || Ctrl('n_porc_emb').TypedValue() == null) && (Ctrl('n_monto_fijo').TypedValue() == 0 || Ctrl('n_monto_fijo').TypedValue() == null))
		{
			alert("Debe cargar un porcentaje y/o un monto fijo a embargar");
		 	return false;
		}
		return true;
	}
	if (Ctrl('c_tipo_embargo').GetXValue() == "OC")
	{
		if (Ctrl('n_monto_total').TypedValue() == 0 || Ctrl('n_monto_total').TypedValue() == null)
		{
			alert("Al Cargar un embargo de tipo Otra Causa debe cargar el monto total");
		 	return false;
		}else
		{
			if (Ctrl('n_monto_pend').GetXValue() == "")
				Ctrl('n_monto_pend').SetCValue(Ctrl('n_monto_total').GetXValue());
		}
		return true;
	}	
}

function Finalizar()
{
	Ctrl('c_estado').SetXValue("F");
	Ctrl('f_finalizado').SetXValue(date2str(Now()));
	ONLOAD();
}

function Inactivar()
{
	if (Ctrl('c_estado').GetXValue() == "I" || Ctrl('c_estado').GetXValue() == "A")
	{
		Ctrl('c_estado').SetXValue("N");
		Ctrl('f_inactivo').SetXValue(date2str(Now()));
		ONLOAD();
		return;
	}
	if (Ctrl('c_estado').GetXValue() == "N")
	{
		Ctrl('c_estado').SetXValue("A");
		Ctrl('f_inactivo').SetXValue("");
		ONLOAD();
		return;
	}

}    

function CambioTipo()
{
	if (Ctrl('c_tipo_embargo').GetXValue() == "CA")
 	{ 		
 		//Ctrl('n_monto_fijo').SetCValue("");
 		Ctrl('n_monto_total').SetCValue("");
 		Ctrl('n_monto_pend').SetCValue("");
 		//Ctrl('oi_concepto').SetXValue("");
 		CtrlEnabled('n_monto_fijo'  , true);
 		CtrlEnabled('n_monto_total' , false);
 		CtrlEnabled('n_monto_pend'  , false);
 		CtrlEnabled('n_porc_emb'    , true);
 		CtrlEnabled('l_sueldo_bruto', true);
 		CtrlEnabled('l_sueldo_neto' , true);
 		CtrlEnabled('oi_concepto'   , true);
 	}                            
 	if (Ctrl('c_tipo_embargo').GetXValue() == "OC")
 	{
 			//Ctrl('n_monto_total').SetCValue("");
 		//Ctrl('n_monto_pend').SetCValue("");
 		Ctrl('n_porc_emb').SetCValue("");
 		//Ctrl('oi_concepto').SetXValue("");
 		Ctrl('l_sueldo_bruto').SetCValue("0");
 		Ctrl('l_sueldo_neto').SetCValue("0");
 		//Ctrl('n_monto_fijo').SetCValue(""); 
 		CtrlEnabled('n_monto_fijo'  , true); 
 		CtrlEnabled('n_monto_total' , true);
 		CtrlEnabled('n_monto_pend'  , true);
 		CtrlEnabled('n_porc_emb'    , false);
 		CtrlEnabled('l_sueldo_bruto', false);
 		CtrlEnabled('l_sueldo_neto' , false);
 		CtrlEnabled('oi_concepto'   , false);




 		//Ctrl('n_monto_total').SetCValue("");
 		//Ctrl('n_monto_pend').SetCValue("");
 		Ctrl('n_porc_emb').SetCValue("");
 		//Ctrl('n_monto_total').SetCValue("");
 		//Ctrl('n_monto_pend').SetCValue("");

 		//Ctrl('oi_concepto').SetXValue("");
 		//Ctrl('l_sueldo_bruto').SetCValue("0");
 		//Ctrl('l_sueldo_neto').SetCValue("0");
 		//Ctrl('n_monto_fijo').SetCValue(""); 
 		CtrlEnabled('n_monto_fijo'  , true); 
 		CtrlEnabled('n_monto_total' , true);
 		CtrlEnabled('n_monto_pend'  , true);
 		CtrlEnabled('n_porc_emb'    , true);
 		CtrlEnabled('l_sueldo_bruto', true);
 		CtrlEnabled('l_sueldo_neto' , true);
 		CtrlEnabled('oi_concepto'   , true);
	}
}
